  "originalFile": "@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800&family=Roboto:wght@300;400;500;600&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* Original Lasarz.com Color Palette */
  --bg-primary: #ffffff;
  --bg-secondary: #f4f6f9;
  --bg-tertiary: #e9ecef;

  --text-primary: #333333;
  --text-secondary: #555555;
  --text-muted: #777777;

  --accent-primary: #1A758D;
  /* The logo highlight blue/teal */
  --accent-secondary: #122b40;
  /* The deep navy blue */
  --accent-glow: rgba(26, 117, 141, 0.1);

  --border-color: #e0e0e0;

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 16px;
  --radius-full: 9999px;

  --space-xs: 0.5rem;
  --space-sm: 1rem;
  --space-md: 2rem;
  --space-lg: 4rem;
  --space-xl: 6rem;
  --space-2xl: 8rem;

  /* Transitions */
  --transition-fast: 0.15s ease-in-out;
  --transition-normal: 0.3s ease-in-out;
  --transition-slow: 0.5s ease-in-out;
}

* {
  box-sizing: border-box;
  padding: 0;
  margin: 0;
}

html,
body {
  max-width: 100vw;
  overflow-x: hidden;
  background-color: var(--bg-primary);
  color: var(--text-primary);
  font-family: 'Roboto', sans-serif;
  line-height: 1.6;
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: 'Poppins', sans-serif;
  color: var(--accent-secondary);
  line-height: 1.2;
}

a {
  color: inherit;
  text-decoration: none;
}

/* Layout Utilities */
.container {
  width: 100%;
  max-width: 1300px;
  margin: 0 auto;
  padding: 0 var(--space-sm);
}

@media (min-width: 768px) {
  .container {
    padding: 0 var(--space-md);
  }
}

.section {
  padding: var(--space-xl) 0;
}

.flex {
  display: flex;
}

.flex-col {
  display: flex;
  flex-direction: column;
}

.items-center {
  align-items: center;
}

.justify-center {
  justify-content: center;
}

.justify-between {
  justify-content: space-between;
}

.gap-sm {
  gap: var(--space-sm);
}

.gap-md {
  gap: var(--space-md);
}

.gap-lg {
  gap: var(--space-lg);
}

/* Grid Utilities */
.grid {
  display: grid;
}

.grid-cols-1 {
  grid-template-columns: repeat(1, minmax(0, 1fr));
}

.grid-cols-2 {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.grid-cols-3 {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.grid-cols-4 {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

@media (max-width: 1024px) {
  .md-grid-cols-2 {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 768px) {
  .sm-grid-cols-1 {
    grid-template-columns: repeat(1, minmax(0, 1fr));
  }

  .hidden-mobile {
    display: none !important;
  }

  .mobile-toggle {
    display: flex !important;
  }

  .section {
    padding: var(--space-lg) 0;
  }

  /* Mobile-specific adjustments for contact form */
  .contact-form-container {
    padding: var(--space-sm);
  }

  .btn {
    width: 100%;
    padding: 1rem 1.5rem;
  }
}

@media (min-width: 768px) {
  .md-flex-row {
    flex-direction: row !important;
    align-items: flex-start;
  }
}

/* Base Components */

.glass-card {
  background: var(--bg-primary);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: var(--space-md);
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  transition: all var(--transition-normal);
  backdrop-filter: blur(10px);
}

.glass-card:hover {
  transform: translateY(-8px);
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
  border-color: var(--accent-primary);
}

.nav-link {
  font-family: 'Poppins', sans-serif;
  font-weight: 500;
  color: var(--accent-secondary);
  position: relative;
  transition: color var(--transition-fast);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 0;
  height: 2px;
  background-color: var(--accent-primary);
  transition: width var(--transition-normal);
}

.nav-link:hover {
  color: var(--accent-primary);
}

.nav-link:hover::after {
  width: 100%;
}

/* Dropdown Menu Styles */
.dropdown-container {
  position: relative;
  display: flex;
  align-items: center;
}

.dropdown-menu {
  position: absolute;
  top: 100%;
  left: 0;
  background: var(--bg-primary);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.1);
  min-width: 280px;
  padding: 1rem 0;
  opacity: 0;
  visibility: hidden;
  transform: translateY(10px);
  transition: all var(--transition-normal);
  z-index: 100;
}

.dropdown-container:hover .dropdown-menu {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

.dropdown-item {
  display: block;
  padding: 0.75rem 1.5rem;
  color: var(--text-secondary);
  font-family: 'Poppins', sans-serif;
  font-size: 0.9rem;
  transition: all var(--transition-fast);
}

.dropdown-item:hover {
  background-color: var(--bg-secondary);
  color: var(--accent-primary);
  padding-left: 2rem;
}

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.75rem;
  border-radius: var(--radius-sm);
  font-family: 'Poppins', sans-serif;
  font-weight: 600;
  font-size: 1rem;
  cursor: pointer;
  transition: all var(--transition-fast);
  border: 1px solid transparent;
  text-decoration: none;
  text-transform: uppercase;
}

.btn-primary {
  background: var(--accent-primary);
  color: #ffffff;
}

.btn-primary:hover {
  background: var(--accent-secondary);
  color: #ffffff;
}

.btn-secondary {
  background: transparent;
  color: var(--accent-secondary);
  border-color: var(--accent-secondary);
}

.btn-secondary:hover {
  background: var(--accent-primary);
  border-color: var(--accent-primary);
  color: #ffffff;
}

.btn-success {
  background: #25d366;
  color: #ffffff;
}

.btn-success:hover {
  background: #128c7e;
  color: #ffffff;
}

.btn-outline {
  background: transparent;
  color: var(--accent-primary);
  border: 1px solid var(--accent-primary);
}

.btn-outline:hover {
  background: var(--accent-primary);
  color: #ffffff;
}

/* Text Effects */
.text-gradient {
  color: var(--accent-secondary);
}

.text-accent {
  color: var(--accent-primary);
}

.text-center {
  text-align: center;
}

/* Animations */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-fade-in {
  animation: fadeIn 0.8s ease-out forwards;
}

.animate-reveal {
  animation: fadeInUp 1s ease-out forwards;
}

.delay-100 {
  animation-delay: 0.1s;
}

.delay-200 {
  animation-delay: 0.2s;
}

.delay-300 {
  animation-delay: 0.3s;
}

/* Form Components */
.form-input {
  width: 100%;
  padding: 0.75rem 1rem;
  background: #ffffff;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-family: 'Roboto', sans-serif;
  transition: all var(--transition-fast);
}

.form-input:focus {
  outline: none;
  border-color: var(--accent-primary);
  box-shadow: 0 0 0 2px var(--accent-glow);
}

/* Legacy components migration for clone */
.footer {
  border-top: 1px solid var(--border-color);
  background-color: var(--bg-secondary);
}

.footer-links {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.footer-links li,
.footer-links a {
  color: var(--text-secondary);
  transition: color var(--transition-fast);
}

.footer-links a:hover {
  color: var(--accent-primary);
}

.footer-bottom {
  margin-top: var(--space-lg);
  padding-top: var(--space-md);
  border-top: 1px solid var(--border-color);
  display: flex;
  justify-content: space-between;
  color: var(--text-muted);
  font-size: 0.875rem;
}

@media (max-width: 768px) {
  .footer-bottom {
    flex-direction: column;
    gap: 1rem;
    align-items: center;
    text-align: center;
  }
}

.sticky-contact-btn:hover {
  transform: scale(1.1);
  background-color: var(--accent-secondary) !important;
}

/* Interactive Map Specific Styles */
.map-container-wrapper {
  position: relative;
  width: 100%;
  aspect-ratio: 1 / 1;
  max-width: 600px;
  margin: 0 auto;
}

@media (min-width: 768px) {
  .map-container-wrapper {
    aspect-ratio: 4 / 3;
    max-width: 800px;
  }
}

.hotspot-wrapper {
  position: absolute;
  transform: translate(-50%, -50%);
  z-index: 20;
}

.hotspot-btn {
  position: relative;
  background-color: var(--accent-secondary);
  color: white;
  padding: 0.5rem 1rem;
  border-radius: var(--radius-full);
  font-size: 0.875rem;
  font-weight: 600;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  white-space: nowrap;
  cursor: pointer;
  border: none;
  transition: all 0.3s ease;
}

.hotspot-btn:hover {
  background-color: var(--accent-primary);
  transform: translateY(-4px);
}

.hotspot-pulsing-dot {
  position: absolute;
  top: -4px;
  right: -4px;
  width: 12px;
  height: 12px;
  background-color: var(--accent-primary);
  border-radius: 50%;
}

.hotspot-pulsing-dot.animate-ping {
  animation: ping 1.5s cubic-bezier(0, 0, 0.2, 1) infinite;
  opacity: 0.75;
}

@keyframes ping {

  75%,
  100% {
    transform: scale(2);
    opacity: 0;
  }
}

.hotspot-tooltip {
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%) translateY(10px);
  margin-top: 1rem;
  width: 280px;
  background-color: white;
  border-radius: var(--radius-md);
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.2);
  padding: 1.25rem;
  border: 1px solid var(--border-color);
  transition: all 0.3s ease;
  pointer-events: none;
  opacity: 0;
  visibility: hidden;
  z-index: 50;
}

.hotspot-tooltip.visible {
  opacity: 1;
  visibility: visible;
  transform: translateX(-50%) translateY(0);
}

.tooltip-triangle {
  position: absolute;
  top: -8px;
  left: 50%;
  transform: translateX(-50%) rotate(45deg);
  width: 16px;
  height: 16px;
  background-color: white;
  border-top: 1px solid var(--border-color);
  border-left: 1px solid var(--border-color);
}

.tooltip-title {
  color: var(--accent-secondary);
  font-weight: bold;
  font-size: 1.125rem;
  margin-bottom: 0.5rem;
  position: relative;
  z-index: 10;
}

/* V3 Premium Utilities */
.glass-premium {
  background: rgba(255, 255, 255, 0.7);
  backdrop-filter: blur(20px) saturate(180%);
  -webkit-backdrop-filter: blur(20px) saturate(180%);
  border: 1px solid rgba(255, 255, 255, 0.3);
  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.07);
}

.hover-lift {
  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 0.3s ease;
}

.hover-lift:hover {
  transform: translateY(-5px) scale(1.02);
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.1);
}

.reveal-on-scroll {
  opacity: 0;
  transform: translateY(30px);
  transition: all 0.8s cubic-bezier(0.5, 0, 0, 1);
}

.reveal-on-scroll.active {
  opacity: 1;
  transform: translateY(0);
}

.star-rating {
  display: inline-flex;
  gap: 2px;
  color: #ffb400;
  font-size: 14px;
}

.star-rating svg {
  width: 14px;
  height: 14px;
  fill: currentColor;
}

@keyframes float {
  0% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
  100% { transform: translateY(0px); }
}

.animate-float {
  animation: float 6s ease-in-out infinite;
}

.text-balance {
  text-wrap: balance;
}

/* V4 Ultra-Premium Calculator Effects */
@keyframes mesh-drift {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.mesh-gradient {
  background: linear-gradient(-45deg, #f4f6f9, #e9ecef, #ffffff, #f4f6f9);
  background-size: 400% 400%;
  animation: mesh-drift 15s ease infinite;
}

@keyframes liquid-flow {
  0% { transform: translateX(-100%) skewX(-20deg); }
  100% { transform: translateX(200%) skewX(-20deg); }
}

.liquid-progress::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 50%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent);
  animation: liquid-flow 2s infinite linear;
}

@keyframes stagger-in {
  0% { opacity: 0; transform: translateY(20px) scale(0.95); }
  100% { opacity: 1; transform: translateY(0) scale(1); }
}

.stagger-item {
  opacity: 0;
  animation: stagger-in 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.breath-glow {
  animation: breath 3s ease-in-out infinite;
}

@keyframes breath {
  0%, 100% { box-shadow: 0 0 5px rgba(26, 117, 141, 0.2); }
  50% { box-shadow: 0 0 20px rgba(26, 117, 141, 0.4); }
}

.tooltip-text {
  color: var(--text-secondary);
  font-size: 0.875rem;
  line-height: 1.5;
  margin: 0;
  position: relative;
  z-index: 10;
}

/* --- Immobilien-Abschreibung Refinement --- */
.immo-glass {
  background: rgba(245, 242, 234, 0.7);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(255, 255, 255, 0.4);
  box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.05);
}

.immo-card-premium {
  background: #ffffff;
  border-radius: 12px;
  border: 1px solid #e0e0e0;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.immo-card-premium:hover {
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
  transform: translateY(-4px);
}

.immo-bg-beige {
  background-color: #F5F2EA;
}

.immo-text-orange {
  color: #FF734D;
}

.immo-btn-green {
  background-color: #00B32E;
  color: #ffffff;
  transition: all 0.2s ease;
}

.immo-btn-green:hover {
  background-color: #008f24;
  transform: translateY(-2px);
